CREATE TABLE `xuntian_work_order` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `plot_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '地块ID',
  `plot_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '地块名称',
  `date` date NOT NULL COMMENT '异常日期',
  `anomaly_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '异常类型（sudden_decline/possible_decline）',
  `anomaly_category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '异常类别（无影像/干旱等）',
  `priority` decimal(10,3) DEFAULT NULL COMMENT '优先级',
  `score` decimal(10,1) DEFAULT NULL COMMENT '评分',
  `multi_index_score` decimal(10,1) DEFAULT NULL COMMENT '多指数评分',
  `area_ratio_delta` decimal(10,3) DEFAULT NULL COMMENT '面积占比变化',
  `area_m2` decimal(10,2) DEFAULT NULL COMMENT '异常面积(㎡)',
  `mean_ndvi` decimal(10,3) DEFAULT NULL COMMENT 'NDVI均值',
  `mean_evi` decimal(10,3) DEFAULT NULL COMMENT 'EVI均值',
  `mean_savi` decimal(10,3) DEFAULT NULL COMMENT 'SAVI均值',
  `mean_ndwi` decimal(10,3) DEFAULT NULL COMMENT 'NDWI均值',
  `delta_ndvi` decimal(10,3) DEFAULT NULL COMMENT 'NDVI变化值',
  `delta_evi` decimal(10,3) DEFAULT NULL COMMENT 'EVI变化值',
  `delta_savi` decimal(10,3) DEFAULT NULL COMMENT 'SAVI变化值',
  `delta_ndwi` decimal(10,3) DEFAULT NULL COMMENT 'NDWI变化值',
  `severity` decimal(10,3) DEFAULT NULL COMMENT '严重程度',
  `edge_ratio` decimal(10,1) DEFAULT NULL COMMENT '边缘占比',
  `centroid` json DEFAULT NULL COMMENT '质心坐标[纬度,经度]',
  `report_png` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '趋势图URL',
  `anomaly_map_png` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '异常图URL',
  `global_suggest_order` int DEFAULT NULL COMMENT '全局建议处理顺序',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='巡田工单表';
